import type { Metadata } from "next"

import { CorporateTaxiScreen } from "./CorporateTaxiScreen"

export const metadata: Metadata = {
  title: "法人配車・タクシーチケット | GO BUSINESS",
  description:
    "法人アカウントでの配車リクエスト・利用目的/プロジェクトコードの登録・タクシーチケットの提示・上長承認の確認・今月の利用明細。",
}

export default function TaxiCorporatePage() {
  return <CorporateTaxiScreen />
}

// Mock domain data for the 法人配車・タクシーチケット screen.
// Pure data (no functions) so it is RSC-safe and can be imported anywhere.

export type AccountKind = "personal" | "corporate"

export interface CorporateAccount {
  /** 会社名 */
  company: string
  /** 利用部署 / 部門 */
  department: string
  /** 社員番号 */
  employeeNo: string
  /** 表示名 */
  memberName: string
}

export const corporateAccount: CorporateAccount = {
  company: "メビウス商事株式会社",
  department: "営業本部 第二営業部",
  employeeNo: "ME-204871",
  memberName: "田村 慧",
}

/** 法人利用ルール（経費規定） */
export interface CorporateRule {
  /** 1回あたりの利用上限 */
  rideCapYen: number
  /** 利用可能時間帯 */
  timeWindow: string
  /** エリア制限 */
  areaLimit: string
  /** 上長承認が必要になる金額しきい値 */
  approvalThresholdYen: number
}

export const corporateRule: CorporateRule = {
  rideCapYen: 8000,
  timeWindow: "平日 8:00–22:00 / 深夜帯は要事前申請",
  areaLimit: "東京23区・周辺主要エリア",
  approvalThresholdYen: 5000,
}

/** 利用目的 */
export interface RidePurpose {
  id: string
  label: string
  /** 補足（どんなときに選ぶか） */
  note: string
  /** この目的で承認が要るか */
  needsApproval: boolean
}

export const ridePurposes: RidePurpose[] = [
  { id: "business", label: "業務移動", note: "取引先訪問・社内拠点間など通常の業務移動", needsApproval: false },
  { id: "entertainment", label: "接待", note: "会食・接待での送迎。上長承認が必要です", needsApproval: true },
  { id: "businesstrip", label: "出張", note: "出張先での移動。プロジェクトコード必須", needsApproval: false },
  { id: "emergency", label: "緊急対応", note: "障害対応・緊急呼び出し。事後申請可", needsApproval: false },
]

/** 費用負担部署の候補 */
export interface CostCenter {
  code: string
  label: string
}

export const costCenters: CostCenter[] = [
  { code: "S2-EIGYO", label: "営業本部 第二営業部（自部署）" },
  { code: "PRJ-AURORA", label: "Auroraリプレース案件" },
  { code: "PRJ-KEIRI", label: "経理基幹刷新PJ" },
  { code: "CS-COMMON", label: "全社共通費" },
]

/** 配車リクエストの初期値（乗車地 / 行き先） */
export const dispatchDraft = {
  pickup: "メビウス商事 本社（東京都港区赤坂2-14-3）",
  dropoff: "グランドニッコー東京 台場",
  estimatedFareYen: 4200,
  etaMinutes: 6,
}

/** タクシーチケット（電子チケット） */
export interface TaxiTicket {
  /** チケット番号 */
  ticketNo: string
  /** スキャン用コード値 */
  codeValue: string
  /** 利用可能額（残高） */
  balanceYen: number
  /** 1回の利用上限 */
  perRideCapYen: number
  /** 有効期限 ISO */
  validUntil: string
  /** 発行元 */
  issuer: string
}

export const taxiTicket: TaxiTicket = {
  ticketNo: "TKT-2026-0066-204871",
  codeValue: "GOBIZ:TKT20260066204871:ME204871",
  balanceYen: 30000,
  perRideCapYen: 8000,
  validUntil: "2026-07-31T23:59:59+09:00",
  issuer: "GO BUSINESS / メビウス商事 法人契約",
}

/** 承認ステータス（この配車に紐づく申請） */
export type ApprovalOutcome = "none" | "pending" | "approved" | "rejected"

export interface ApprovalState {
  outcome: ApprovalOutcome
  /** 申請番号 */
  requestNo: string
  approver: string
  submittedAt: string
  decidedAt?: string
  comment?: string
}

export const approvalState: ApprovalState = {
  outcome: "pending",
  requestNo: "AP-2026-1180",
  approver: "近藤 部長",
  submittedAt: "06/28 14:02",
}

/** 今月の利用明細 */
export interface UsageEntry {
  id: string
  datetime: string
  route: string
  purposeLabel: string
  amountYen: number
  approval: ApprovalOutcome
}

